# run_results_parser.py
# Parses dbt run_results.json and extracts model execution metrics.
# Returns a dictionary keyed by model name containing
# refresh time, duration, rows affected, and status.
#
# Source: target/run_results.json
# Generated by: dbt run, dbt build
#
# _preprocess filters to model results only — discards tests and seeds
# _parse_file extracts timing, rows affected, and status per model

import logging
from datetime import datetime
from .base_parser import BaseParser

logger = logging.getLogger(__name__)


class RunResultsParser(BaseParser):

    def _cache_name(self) -> str:
        return 'run_results'

    def _preprocess(self, data: dict) -> dict:
        # keep only model results — discard test and seed results
        # keep all fields within each model result
        return {
            'results': [
                result for result in data.get('results', [])
                if result.get('unique_id', '').startswith('model.')
            ],
            'metadata': data.get('metadata', {})
        }

    def _parse_file(self, data: dict) -> dict:
        run_results = {}
        results = data.get('results', [])
        generated_at = data.get('metadata', {}).get('generated_at', '')

        for result in results:
            unique_id = result.get('unique_id', '')

            # extract model name from unique_id
            # e.g. 'model.jaffle_shop.orders' → 'orders'
            model_name = unique_id.split('.')[-1]
            if not model_name:
                continue

            logger.info(f"Parsing run result: {model_name}")

            # extract execute timing block only
            # timing array contains compile and execute blocks
            # we only care about execute — when data was written
            execute_timing = next(
                (t for t in result.get('timing', [])
                 if t.get('name') == 'execute'),
                None
            )

            # calculate refresh duration from execute timing
            duration_seconds = None
            last_refreshed = None

            if execute_timing:
                started = execute_timing.get('started_at', '')
                completed = execute_timing.get('completed_at', '')

                if started and completed:
                    try:
                        started_dt = datetime.fromisoformat(
                            started.replace('Z', '+00:00')
                        )
                        completed_dt = datetime.fromisoformat(
                            completed.replace('Z', '+00:00')
                        )
                        duration_seconds = (
                            completed_dt - started_dt
                        ).total_seconds()
                        last_refreshed = completed
                    except ValueError as e:
                        logger.error(
                            f"Failed to parse timing for "
                            f"{model_name}: {e}"
                        )

            # rows affected from adapter response
            rows_affected = result.get(
                'adapter_response', {}
            ).get('rows_affected')

            # execution status
            status = result.get('status', '')

            run_results[model_name] = {
                'last_refreshed': last_refreshed or generated_at,
                'refresh_duration_seconds': duration_seconds,
                'rows_added': rows_affected,
                'status': status,
            }

        logger.info(
            f"Parsed {len(run_results)} model results "
            f"from run_results.json"
        )
        return run_results